func auditCSVContacts(contacts []csvContact, lists []int) map[string]any {
	seen := map[string]int{}
	invalid := []map[string]any{}
	duplicates := []map[string]any{}
	valid := 0
	for i, row := range contacts {
		email := normalizeEmail(row.Email)
		if _, err := mail.ParseAddress(row.Email); err != nil || email == "" {
			invalid = append(invalid, map[string]any{"row": i + 2, "email": row.Email, "error": "invalid_email"})
			continue
		}
		valid++
		seen[email]++
		if seen[email] == 2 {
			duplicates = append(duplicates, map[string]any{"email": email, "reason": "duplicate_in_csv"})
		}
	}
	return map[string]any{"rows": len(contacts), "valid_emails": valid, "invalid_count": len(invalid), "duplicate_count": len(duplicates), "planned_lists": lists, "invalid": invalid, "duplicates": duplicates, "safe_import_command": "sendfox-pp-cli contacts import-csv --file <csv> --lists <ids> --dry-run --agent"}
}

func hygieneReport(contacts, lists []map[string]any) map[string]any {
	seen := map[string]int{}
	duplicates := []map[string]any{}
	invalid := []map[string]any{}
	statusCounts := map[string]int{}
	withoutLists := 0
	for _, ct := range contacts {
		email, _ := ct["email"].(string)
		norm := normalizeEmail(email)
		if norm == "" {
			invalid = append(invalid, map[string]any{"contact": ct, "reason": "missing_email"})
		} else if _, err := mail.ParseAddress(email); err != nil {
			invalid = append(invalid, map[string]any{"email": email, "reason": "invalid_email"})
		}
		if norm != "" {
			seen[norm]++
			if seen[norm] == 2 {
				duplicates = append(duplicates, map[string]any{"email": norm})
			}
		}
		status, _ := ct["status"].(string)
		if status == "" {
			status = "unknown"
		}
		statusCounts[status]++
		if len(contactListIDs(ct)) == 0 {
			withoutLists++
		}
	}
	return map[string]any{
		"generated_at":             time.Now().UTC().Format(time.RFC3339),
		"contact_count":            len(contacts),
		"list_count":               len(lists),
		"status_counts":            statusCounts,
		"invalid_email_count":      len(invalid),
		"duplicate_email_count":    len(duplicates),
		"contacts_without_lists":   withoutLists,
		"duplicates":               duplicates,
		"invalid":                  invalid,
		"lists_by_membership_hint": rankListsByObservedMembership(lists, contacts, 25),
		"recommended_next_commands": []string{
			"sendfox-pp-cli contacts audit-csv --file subscribers.csv --agent",
			"sendfox-pp-cli contacts reconcile-csv --file subscribers.csv --lists <ids> --dry-run --agent",
			"sendfox-pp-cli workflow audience-map --agent",
		},
	}
}

func launchPlanPayload(listID int, campaignName, landingURL, csvPath string, list map[string]any) map[string]any {
	label := strings.TrimSpace(campaignName)
	if label == "" {
		label = fmt.Sprintf("list-%d-launch", listID)
	}
	commands := []string{
		fmt.Sprintf("sendfox-pp-cli lists get --list-id %d --agent", listID),
		fmt.Sprintf("sendfox-pp-cli forms generate --list-id %d --title %q --agent", listID, label),
		"sendfox-pp-cli workflow audience-map --agent",
	}
	if csvPath != "" {
		commands = append(commands,
			fmt.Sprintf("sendfox-pp-cli contacts audit-csv --file %s --lists %d --agent", shellish(csvPath), listID),
			fmt.Sprintf("sendfox-pp-cli contacts import-csv --file %s --lists %d --dry-run --agent", shellish(csvPath), listID),
		)
	}
	steps := []string{"Validate the target list exists.", "Generate or verify signup form/server proxy.", "Audit and dry-run any subscriber CSV before live import.", "Create/send the campaign in SendFox dashboard; the public docs only expose campaign read endpoints.", "Run workflow campaign-digest after send to capture campaign inventory."}
	return map[string]any{"campaign_name": label, "list_id": listID, "list": list, "landing_url": landingURL, "commands": commands, "steps": steps, "api_gap": "SendFox public docs expose campaign list/get only, so campaign creation/sending is a dashboard step, not a fake CLI write."}
}

func normalizeEmail(email string) string { return strings.ToLower(strings.TrimSpace(email)) }

func shellish(value string) string {
	if strings.ContainsAny(value, " \t\n'\"") {
		return fmt.Sprintf("%q", value)
	}
	return value
}

func sortedCapabilityNames() []string {
	caps := sendfoxCapabilities()
	out := make([]string, 0, len(caps))
	for _, cap := range caps {
		out = append(out, cap.Resource)
	}
	sort.Strings(out)
	return out
}
